package com.izonehub.stores.auth;import com.izonehub.stores.user.*;import jakarta.validation.Valid;import org.springframework.beans.factory.annotation.Value;import org.springframework.http.HttpStatus;import org.springframework.security.crypto.password.PasswordEncoder;import org.springframework.web.bind.annotation.*;import org.springframework.web.server.ResponseStatusException;
@RestController @RequestMapping("/api/auth") public class AuthController{private final UserRepository users;private final PasswordEncoder encoder;private final JwtService jwt;private final int maxFailed;public AuthController(UserRepository users,PasswordEncoder encoder,JwtService jwt,@Value("${app.security.max-failed-logins}")int maxFailed){this.users=users;this.encoder=encoder;this.jwt=jwt;this.maxFailed=maxFailed;} @PostMapping("/login") public AuthDtos.LoginResponse login(@Valid @RequestBody AuthDtos.LoginRequest req){AppUser u=users.findByEmail(req.email().toLowerCase()).orElseThrow(()->new ResponseStatusException(HttpStatus.UNAUTHORIZED)); if(!u.isActive()||u.isLocked())throw new ResponseStatusException(HttpStatus.UNAUTHORIZED); if(!encoder.matches(req.password(),u.getPasswordHash())){u.recordFailedLogin(maxFailed);users.save(u);throw new ResponseStatusException(HttpStatus.UNAUTHORIZED);} u.recordSuccessfulLogin();users.save(u);return new AuthDtos.LoginResponse(jwt.issueAccessToken(u),u.isForcePasswordChange());}}
